use once_cell::sync::Lazy;
use std::sync::Arc;
static CACHE: Lazy<Mutex<HashMap<i32, Arc<[TypeTreeNode]>>>> = Lazy::new(|| Mutex::new(HashMap::new()));
pub fn get_fallback_nodes(class_id: i32) -> Arc<[TypeTreeNode]> {
    let mut cache = CACHE.lock().unwrap();
    if let Some(nodes) = cache.get(&class_id) {
        return nodes.clone();
    }
    let nodes: Arc<[TypeTreeNode]> = get_fallback_nodes_uncached(class_id).into();
    cache.insert(class_id, nodes.clone());
    nodes
}
